<!-- components/orderDetail.vue -->
<template>
	<div class="order-card">
		<div class="box">
			<p class="cp"><strong>订单号:</strong>{{ order_id }}</p>
			<div class="status_div cp">
				<view class="colorLump" :style="{ backgroundColor: getStatusColor(status) }"></view>
				<span><strong>订单状态:</strong>{{ status }}</span>
			</div>
			<div class="product-details">
				<p class="cp"><strong>订单详情:</strong></p>
				<p class="bp">产品编号: {{ product }}</p>
				<p class="bp">数量: {{ number }}</p>
				<p class="bp">单价: {{ singlePrice }}$</p>
				<p class="cp"><strong>总价:</strong>{{ totalPrice }}$</p>
			</div>
			<div class="date">
				<div class="time-range">
					<view class='aspan'>{{ startDate }}</view>
					<view class='bspan'>至</view>
					<view class='aspan'>{{ endDate }}</view>
				</div>
			</div>
		</div>
	</div>
</template>

<script setup>
	import {
		defineProps
	} from 'vue'

	const props = defineProps({
		order_id: {
			type: String,
			default: ''
		},
		status: {
			type: String,
			default: ''
		},
		product: {
			type: String,
			default: ''
		},
		number: {
			type: Number,
			default: ''
		},
		singlePrice: {
			type: Number,
			default: ''
		},
		totalPrice: {
			type: Number,
			default: ''
		},
		startDate: {
			type: String,
			default: ''
		},
		endDate: {
			type: String,
			default: ''
		}
	})

	// 根据状态返回颜色
	const getStatusColor = (status) => {
		if (!status) return '#999'
		if (status.includes('completed')) return '#4CAF50'
		if (status.includes('processing') || status.includes('pending')) return '#2196F3'
		if (status.includes('cancelled')) return '#F44336'
		return '#FF9800'
	}
</script>

<style scoped>
	/* 保持原有样式不变 */
	.bp {
		margin-left: 40rpx;
		margin-top: 10rpx;
	}

	.cp {
		margin-top: 30px;
		font-size: 36rpx;
	}

	.box {
		margin-top: 20rpx;
		border-radius: 50rpx;
		padding: 3rpx;
		background-color: rgba(253, 253, 253, 0.6);
		flex-direction: column;
		gap: 10rpx;
		/* border: 1px skyblue solid; */
	}

	.colorLump {
		border-radius: 100rpx;
		width: 40rpx;
		height: 40rpx;
		margin-right: 20rpx;
	}

	.status_div {
		display: flex;
		flex-direction: row;
		align-items: center;
	}

	.date {
		display: flex;
		justify-content: flex-end;
		margin-top: 30px;
	}

	.time-range {
		display: flex;
		align-items: center;
		gap: 12rpx;
	}

	.aspan {
		padding: 8rpx 12rpx;
		text-align: center;
		white-space: nowrap;
		font-size: 28rpx;
		flex: 1;
	}

	.bspan {
		font-weight: bold;
		color: #555;
		font-size: 28rpx;
		padding: 0 8rpx;
	}
</style>